class Solution {
public:
    int strongPasswordChecker(string password) {
        int n = password.size();
        int oneLower = 1, oneUpper = 1, oneDigit = 1;
        for (char c : password) {
            if (islower(c)) oneLower = 0;
            if (isupper(c)) oneUpper = 0;
            if (isdigit(c)) oneDigit = 0;
        }

        int replace = 0, delThree = 0, i = 2;
        while (i < n) {
            if (password[i] == password[i-1] && password[i] == password[i-2]) {
                int j = i;
                while (j < n && password[j] == password[i]) j++;
                delThree += (j - i) / 3;
                i = j;
            }
            i++;
        }

        int res = 0;
        if (n < 6) {
            res = 6 - n + oneLower + oneUpper + oneDigit;
        } else {
            res = oneLower + oneUpper + oneDigit;
            if (n <= 20) {
                res += max(0, delThree);
            } else {
                int del = n - 20;
                res += del;
                delThree -= del;
                res += max(0, delThree);
            }
        }
        return res;
    }
};
